using System.Collections.Generic;
using System.Linq;
using System.Web.Mvc;
using YourNamespace.Models; // Replace with your actual namespace

public class ReviewsController : Controller
{
    private YourDbContext _context; // Replace with your actual DbContext

    public ReviewsController()
    {
        _context = new YourDbContext(); // Initialize your DbContext
    }

    public ActionResult Index(int productId)
    {
        var reviews = _context.Reviews
            .Where(r => r.ProductId == productId)
            .ToList();

        return View(reviews);
    }

    [HttpPost]
    public ActionResult SubmitReview(Review review)
    {
        if (ModelState.IsValid)
        {
            _context.Reviews.Add(review);
            _context.SaveChanges();
            return RedirectToAction("Index", new { productId = review.ProductId });
        }

        return View(review);
    }
}

@model IEnumerable<YourNamespace.Models.Review> // Replace with your actual namespace

@{
    ViewBag.Title = "Product Reviews";
}

<h2>Product Reviews</h2>

@foreach (var review in Model)
{
    <div>
        <h4>@review.UserName</h4>
        <p>@Html.Raw(review.Content)</p>
        <small>@review.SubmittedOn.ToString("g")</small>
    </div>
}

<form method="post" action="@Url.Action("SubmitReview", "Reviews")">
    @Html.Hidden("ProductId", Model.First().ProductId)
    <div>
        <label for="UserName">Name:</label>
        <input type="text" name="UserName" required />
    </div>
    <div>
        <label for="Content">Review:</label>
        <textarea name="Content" required></textarea>
    </div>
    <button type="submit">Submit Review</button>
</form>